insert into public.demo_space_operators(name) select '모디자 데모 공간 운영자' where not exists(select 1 from public.demo_space_operators);
insert into public.spaces(operator_id,name,slug,space_type,short_description,description,main_region,detailed_region,address,price_per_hour,minimum_hours,suitable_capacity,max_capacity,available_days,available_start_time,available_end_time,regular_use_available,facilities,moods,suitable_activities,noise_level,food_allowed,parking_available,thumbnail_url,status) select o.id,v.* from public.demo_space_operators o cross join(values
('동성로 소규모 문화공간','dongseong-culture-space','복합문화공간','작은 모임에 온기를 더하는 문화공간','영화모임과 북토크, 네트워킹에 잘 어울리는 공간입니다.','동성로','교동','대구 중구 교동길 10',30000,2,12,20,array['월','화','수','목','금','토'],time '10:00',time '22:00',true,array['빔프로젝터','스피커'],array['따뜻한','감각적인'],array['영화모임','네트워킹'], 'moderate',true,false,'https://images.unsplash.com/photo-1497366811353-6870744d04b2?auto=format&fit=crop&w=1200&q=80','active'),
('수성못 카페형 모임 공간','suseong-lake-cafe','카페','자연광이 머무는 조용한 카페형 공간','독서와 글쓰기, 스터디를 위한 긴 테이블이 있습니다.','수성못','수성못','대구 수성구 수성못길 20',25000,2,8,12,array['화','수','목','금','토','일'],time '09:00',time '21:00',true,array['긴 테이블','와이파이'],array['조용한','자연광이 좋은'],array['독서모임','글쓰기','스터디'],'quiet',true,true,'https://images.unsplash.com/photo-1497366754035-f200968a6e72?auto=format&fit=crop&w=1200&q=80','active'),
('경북대 스터디룸','knu-study-room','회의실','집중하기 좋은 밝은 스터디룸','화이트보드와 넉넉한 콘센트를 갖춘 공간입니다.','경북대','복현동','대구 북구 복현로 30',18000,1,8,10,array['월','화','수','목','금','토','일'],time '08:00',time '23:00',true,array['화이트보드','콘센트'],array['전문적인','밝은'],array['스터디','보드게임'],'moderate',false,false,'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&w=1200&q=80','active'),
('앞산 감성 스튜디오','apsan-studio','스튜디오','촬영과 클래스가 어울리는 감성 스튜디오','조명과 스피커를 갖춘 독특한 분위기의 공간입니다.','앞산','대명동','대구 남구 대명로 40',40000,2,10,15,array['수','목','금','토','일'],time '10:00',time '22:00',false,array['스피커','냉난방'],array['감각적인','독특한'],array['촬영','원데이 클래스'],'active',true,true,'https://images.unsplash.com/photo-1497366753845-f200968a6e72?auto=format&fit=crop&w=1200&q=80','active'))v(name,slug,space_type,short_description,description,main_region,detailed_region,address,price_per_hour,minimum_hours,suitable_capacity,max_capacity,available_days,available_start_time,available_end_time,regular_use_available,facilities,moods,suitable_activities,noise_level,food_allowed,parking_available,thumbnail_url,status);
insert into public.space_images(space_id,storage_path,public_url,file_name,mime_type,sort_order,is_thumbnail) select id,'seed/'||slug||'.webp',thumbnail_url,slug||'.webp','image/webp',0,true from public.spaces where slug in('dongseong-culture-space','suseong-lake-cafe','knu-study-room','apsan-studio') on conflict(storage_path) do nothing;
